namespace RecipeShare.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Ingredients { get; set; } = string.Empty;
    public string Steps { get; set; } = string.Empty;
    public double AverageRating { get; set; }
    public int RatingCount { get; set; }
}

using RecipeShare.Models;

namespace RecipeShare.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes = new()
    {
        new Recipe { Id = 1, Title = "Classic Margherita Pizza", Category = "Italian", Ingredients = "Pizza dough
Mozzarella cheese
Fresh basil
San Marzano tomatoes
Olive oil
Salt", Steps = "1. Preheat oven to 475°F.
2. Roll out dough on a floured surface.
3. Spread crushed tomatoes evenly.
4. Add sliced mozzarella.
5. Bake for 10-12 minutes.
6. Top with fresh basil and drizzle olive oil.", AverageRating = 4.5, RatingCount = 12 },
        new Recipe { Id = 2, Title = "Spaghetti Carbonara", Category = "Italian", Ingredients = "Spaghetti
Pancetta
Eggs
Parmesan cheese
Black pepper
Salt", Steps = "1. Cook spaghetti al dente.
2. Fry pancetta until crispy.
3. Whisk eggs with grated Parmesan.
4. Toss hot pasta with pancetta.
5. Remove from heat and stir in egg mixture.
6. Season with black pepper.", AverageRating = 4.8, RatingCount = 20 },
        new Recipe { Id = 3, Title = "Chicken Tikka Masala", Category = "Indian", Ingredients = "Chicken breast
Yogurt
Garam masala
Turmeric
Tomato sauce
Heavy cream
Onion
Garlic
Ginger", Steps = "1. Marinate chicken in yogurt and spices for 2 hours.
2. Grill or bake marinated chicken.
3. Sauté onion, garlic, and ginger.
4. Add tomato sauce and spices.
5. Simmer, then add cream.
6. Add chicken pieces and cook 10 minutes.", AverageRating = 4.7, RatingCount = 15 },
        new Recipe { Id = 4, Title = "Vegetable Pad Thai", Category = "Thai", Ingredients = "Rice noodles
Tofu
Bean sprouts
Peanuts
Lime
Fish sauce
Tamarind paste
Garlic
Eggs", Steps = "1. Soak rice noodles in warm water.
2. Press and cube tofu, then fry until golden.
3. Scramble eggs in wok.
4. Add noodles, tamarind paste, and fish sauce.
5. Toss with bean sprouts.
6. Serve with crushed peanuts and lime.", AverageRating = 4.3, RatingCount = 8 },
        new Recipe { Id = 5, Title = "Beef Tacos", Category = "Mexican", Ingredients = "Ground beef
Taco shells
Lettuce
Tomato
Cheddar cheese
Sour cream
Taco seasoning
Onion", Steps = "1. Brown ground beef with diced onion.
2. Add taco seasoning and water.
3. Simmer until thickened.
4. Warm taco shells.
5. Fill with beef and top with lettuce, tomato, cheese.
6. Add sour cream to taste.", AverageRating = 4.2, RatingCount = 10 },
        new Recipe { Id = 6, Title = "Chocolate Lava Cake", Category = "Desserts", Ingredients = "Dark chocolate
Butter
Eggs
Sugar
Flour
Vanilla extract", Steps = "1. Melt chocolate and butter together.
2. Whisk eggs and sugar until fluffy.
3. Fold in chocolate mixture.
4. Add flour and vanilla.
5. Pour into greased ramekins.
6. Bake at 425°F for 12 minutes.
7. Invert onto plate and serve immediately.", AverageRating = 4.9, RatingCount = 25 },
    };

    private int _nextId = 7;

    public List<string> GetCategories()
    {
        return _recipes.Select(r => r.Category).Distinct().OrderBy(c => c).ToList();
    }

    public List<Recipe> GetByCategory(string category)
    {
        return _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();
    }

    public Recipe? GetById(int id)
    {
        return _recipes.FirstOrDefault(r => r.Id == id);
    }

    public void AddRating(int recipeId, int stars)
    {
        var recipe = GetById(recipeId);
        if (recipe is null || stars < 1 || stars > 5) return;

        var totalStars = recipe.AverageRating * recipe.RatingCount + stars;
        recipe.RatingCount++;
        recipe.AverageRating = Math.Round(totalStars / recipe.RatingCount, 1);
    }

    public void AddRecipe(Recipe recipe)
    {
        recipe.Id = _nextId++;
        _recipes.Add(recipe);
    }
}

