arguments.file_text:
@page "/categories"
@inject RecipeShare.Services.RecipeService RecipeService

<PageTitle>Browse Categories</PageTitle>

<h1>Recipe Categories</h1>
<p>Choose a category to browse recipes.</p>

<div class="list-group">
    @foreach (var category in RecipeService.GetCategories())
    {
        <a href="@($"categories/{category}")" class="list-group-item list-group-item-action d-flex justify-content-between align-items-center">
            @category
            <span class="badge bg-primary rounded-pill">@RecipeService.GetByCategory(category).Count</span>
        </a>
    }
</div>

@page "/categories/{CategoryName}"
@inject RecipeShare.Services.RecipeService RecipeService

<PageTitle>@CategoryName Recipes</PageTitle>

<h1>@CategoryName Recipes</h1>
<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="categories">Categories</a></li>
        <li class="breadcrumb-item active">@CategoryName</li>
    </ol>
</nav>

@if (Recipes.Any())
{
    <div class="row">
        @foreach (var recipe in Recipes)
        {
            <div class="col-md-6 mb-3">
                <div class="card">
                    <div class="card-body">
                        <h5 class="card-title">@recipe.Title</h5>
                        <p class="card-text">
                            ⭐ @recipe.AverageRating / 5 (@recipe.RatingCount ratings)
                        </p>
                        <a href="@($"recipe/{recipe.Id}")" class="btn btn-outline-primary">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}
else
{
    <div class="alert alert-info">No recipes found in this category.</div>
}

@code {
    [Parameter]
    public string CategoryName { get; set; } = string.Empty;

    private List<RecipeShare.Models.Recipe> Recipes { get; set; } = new();

    protected override void OnParametersSet()
    {
        Recipes = RecipeService.GetByCategory(CategoryName);
    }
}

@page "/recipe/{Id:int}"
@inject RecipeShare.Services.RecipeService RecipeService

<PageTitle>@(Recipe?.Title ?? "Recipe")</PageTitle>

@if (Recipe is null)
{
    <div class="alert alert-warning">Recipe not found.</div>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="categories">Categories</a></li>
            <li class="breadcrumb-item"><a href="@($"categories/{Recipe.Category}")">@Recipe.Category</a></li>
            <li class="breadcrumb-item active">@Recipe.Title</li>
        </ol>
    </nav>

    <h1>@Recipe.Title</h1>
    <p class="text-muted">Category: @Recipe.Category</p>

    <h3>Ingredients</h3>
    <ul>
        @foreach (var ingredient in Recipe.Ingredients.Split('\n', StringSplitOptions.RemoveEmptyEntries))
        {
            <li>@ingredient</li>
        }
    </ul>

    <h3>Steps</h3>
    @foreach (var step in Recipe.Steps.Split('\n', StringSplitOptions.RemoveEmptyEntries))
    {
        <p>@step</p>
    }

    <hr />

    <h3>Rate This Recipe</h3>
    <p>Average: ⭐ @Recipe.AverageRating / 5 (@Recipe.RatingCount ratings)</p>

    <StarRating RecipeId="Recipe.Id" />
}

@code {
    [Parameter]
    public int Id { get; set; }

    private RecipeShare.Models.Recipe? Recipe { get; set; }

    protected override void OnParametersSet()
    {
        Recipe = RecipeService.GetById(Id);
    }
}

@rendermode InteractiveServer
@inject RecipeShare.Services.RecipeService RecipeService

<div class="star-rating">
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span class="star @(star <= SelectedRating ? "selected" : "")"
              @onclick="() => Rate(star)"
              style="cursor: pointer; font-size: 2rem;">
            @(star <= SelectedRating ? "★" : "☆")
        </span>
    }
</div>

@if (Submitted)
{
    <div class="alert alert-success mt-2">
        Thanks! You rated this recipe @SelectedRating star@(SelectedRating != 1 ? "s" : "").
    </div>
}

@code {
    [Parameter]
    public int RecipeId { get; set; }

    private int SelectedRating { get; set; }
    private bool Submitted { get; set; }

    private void Rate(int stars)
    {
        SelectedRating = stars;
        RecipeService.AddRating(RecipeId, stars);
        Submitted = true;
    }
}

@page "/submit"
@rendermode InteractiveServer
@inject RecipeShare.Services.RecipeService RecipeService
@inject NavigationManager Navigation

<PageTitle>Submit a Recipe</PageTitle>

<h1>Submit a Recipe</h1>
<p>Share your favorite recipe with the community!</p>

@if (SubmitSuccess)
{
    <div class="alert alert-success">
        <strong>Recipe submitted!</strong> Your recipe "@Model.Title" has been added.
        <a href="@($"recipe/{SubmittedId}")">View it here</a>.
    </div>
}

<EditForm Model="Model" OnValidSubmit="HandleSubmit" FormName="submit-recipe">
    <DataAnnotationsValidator />
    <ValidationSummary class="text-danger" />

    <div class="mb-3">
        <label for="title" class="form-label">Recipe Title</label>
        <InputText id="title" class="form-control" @bind-Value="Model.Title" placeholder="e.g., Grandma's Apple Pie" />
        <ValidationMessage For="() => Model.Title" />
    </div>

    <div class="mb-3">
        <label for="category" class="form-label">Category</label>
        <InputSelect id="category" class="form-select" @bind-Value="Model.Category">
            <option value="">-- Select a category --</option>
            @foreach (var cat in RecipeService.GetCategories())
            {
                <option value="@cat">@cat</option>
            }
            <option value="Other">Other</option>
        </InputSelect>
        <ValidationMessage For="() => Model.Category" />
    </div>

    <div class="mb-3">
        <label for="ingredients" class="form-label">Ingredients (one per line)</label>
        <InputTextArea id="ingredients" class="form-control" rows="6" @bind-Value="Model.Ingredients" placeholder="1 cup flour&#10;2 eggs&#10;1/2 cup sugar" />
